245	void qSlicerAppMainWindow::on_HelpKeyboardShortcutsAction_triggered()
246	{
247	  qSlicerActionsDialog actionsDialog(this);
248	  actionsDialog.setActionsWithNoShortcutVisible(false);
249	  actionsDialog.setMenuActionsVisible(false);
250	  actionsDialog.addActions(this->findChildren<QAction*>(), "Slicer Application");
251	
252	  // scan the modules for their actions
253	  QList<QAction*> moduleActions;
254	  qSlicerModuleManager* moduleManager = qSlicerApplication::application()->moduleManager();
255	  for (const QString& moduleName : moduleManager->modulesNames())
256	  {
257	    qSlicerAbstractModule* module = qobject_cast<qSlicerAbstractModule*>(moduleManager->module(moduleName));
258	    if (module)
259	    {
260	      moduleActions << module->action();
261	    }
262	  }
263	  if (moduleActions.size())
264	  {
265	    actionsDialog.addActions(moduleActions, "Modules");
266	  }
267	  // TODO add more actions
268	  actionsDialog.exec();
269	}
